     1→import { WhatsAppButton } from '@/components/WhatsAppButton';
     2→import { useAuth } from '@/contexts/AuthContext';
     3→import { subscriptionState } from '@/services/subscriptionState';
     4→import { ReactNode, useEffect } from 'react';
     5→import { useLocation, useNavigate } from 'react-router-dom';
     6→
     7→interface ProtectedRouteProps {
     8→  children: ReactNode;
     9→  requiredRole?: 'Easy Salon' | 'Tenant Admin' | 'Profissional' | 'Recepcionista' | 'Administrador';
    10→  allowedRoles?: ('Easy Salon' | 'Tenant Admin' | 'Profissional' | 'Recepcionista' | 'Administrador')[];
    11→}
    12→
    13→export function ProtectedRoute({ children, requiredRole, allowedRoles }: ProtectedRouteProps) {
    14→  const { isAuthenticated, user, isLoading } = useAuth();
    15→  const navigate = useNavigate();
    16→  const location = useLocation();
    17→
    18→  useEffect(() => {
    19→    // Não fazer nada enquanto está carregando
    20→    if (isLoading) {
    21→      return;
    22→    }
    23→
    24→    // Se não estiver autenticado, redireciona para login
    25→    if (!isAuthenticated) {
    26→      navigate('/login', {
    27→        replace: true,
    28→        state: { from: location.pathname }
    29→      });
    30→      return;
    31→    }
    32→
    33→    // Usuários não admin não podem acessar área admin
    34→    if (user?.role !== 'Easy Salon' && user?.role !== 'Tenant Admin' && location.pathname.startsWith('/admin/')) {
    35→      navigate('/salon/agenda', { replace: true });
    36→      return;
    37→    }
    38→
    39→    // Verificar permissões por roles permitidas
    40→    if (allowedRoles && user?.role && !allowedRoles.includes(user.role)) {
    41→      if (user?.role === 'Easy Salon' || user?.role === 'Tenant Admin') {
    42→        navigate('/admin/salons', { replace: true });
    43→      } else {
    44→        navigate('/salon/agenda', { replace: true });
    45→      }
    46→      return;
    47→    }
    48→
    49→    // Verificar permissão por role específica (mantém compatibilidade)
    50→    if (requiredRole && user?.role !== requiredRole) {
    51→      // Easy Salon e Tenant Admin podem acessar tudo (admin e salon)
    52→      if (user?.role === 'Easy Salon' || user?.role === 'Tenant Admin') {
    53→        return;
    54→      }
    55→
    56→      // Administrador pode acessar área do salão
    57→      if (user?.role === 'Administrador' && !location.pathname.startsWith('/admin/')) {
    58→        return;
    59→      }
    60→
    61→      // Redirecionar para a área apropriada se não tem permissão
    62→      if (location.pathname.startsWith('/admin/')) {
    63→        navigate('/salon/agenda', { replace: true });
    64→      } else {
    65→        navigate('/admin/salons', { replace: true });
    66→      }
    67→    }
    68→
    69→    // --- SUBSCRIPTION CHECK ---
    70→    // Super Admin (Easy Salon) and Tenant Admin bypass subscription checks.
    71→    // Tenant Admins manage payments from /salon/my-plan and may freely switch salons;
    72→    // the per-salon enforcement happens via the httpClient 403 interceptor when they
    73→    // make actual API calls to guarded salon endpoints.
    74→    const isSuperUser = user?.role === 'Easy Salon' || user?.role === 'Tenant Admin';
    75→    const allowedStatuses = ['active', 'trialing'];
    76→
    77→    if (!isLoading && !isSuperUser) {
    78→      // A salon-bound user (Administrador, Profissional, Recepcionista) MUST have an
    79→      // explicit valid subscriptionStatus. undefined / 'none' / 'past_due' / 'canceled'
    80→      // all trigger the enforcement modal. This is fail-closed by design.
    81→      const isSalonBoundUser = !!user?.salonId;
    82→      const isUserStatusInvalid = isSalonBoundUser && !allowedStatuses.includes(user?.subscriptionStatus ?? '');
    83→
    84→      const isProtectedPath = !location.pathname.startsWith('/salon/my-plan') && !location.pathname.startsWith('/login');
    85→
    86→      if (isUserStatusInvalid && isProtectedPath) {
    87→        // Delegate to GlobalSubscriptionManager (single source of truth for the modal).
    88→        // This also works correctly when the user switches salons: useSelectedSalon
    89→        // calls subscriptionState.setExpired(false) on salon change, then a new probe
    90→        // or the next 403 will re-set it if the new salon is also inactive.
    91→        subscriptionState.setExpired(true);
    92→      } else if (!isUserStatusInvalid) {
    93→        // Clear only if we know the status is valid — don't clear on undefined to
    94→        // avoid a race window where the probe hasn't responded yet.
    95→        if (user?.subscriptionStatus && allowedStatuses.includes(user.subscriptionStatus)) {
    96→          subscriptionState.setExpired(false);
    97→        }
    98→      }
    99→    }
   100→
   101→  }, [isAuthenticated, user, user?.subscriptionStatus, location.pathname, navigate, requiredRole, isLoading]);
   102→
   103→
   104→  // Se está carregando, mostrar loading spinner
   105→  if (isLoading) {
   106→    return (
   107→      <div className="flex items-center justify-center min-h-screen">
   108→        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
   109→      </div>
   110→    );
   111→  }
   112→
   113→  // Se não está autenticado, não renderiza nada (já está redirecionando)
   114→  if (!isAuthenticated) {
   115→    return null;
   116→  }
   117→
   118→  // Se há conflito de role, não renderiza nada (já está redirecionando)
   119→  if (user?.role !== 'Easy Salon' && user?.role !== 'Tenant Admin' && location.pathname.startsWith('/admin/')) {
   120→    return null;
   121→  }
   122→
   123→  // Verificar permissões
   124→  let hasPermission = true;
   125→
   126→  if (allowedRoles && user?.role && !allowedRoles.includes(user.role)) {
   127→    hasPermission = false;
   128→  }
   129→
   130→  if (hasPermission && requiredRole && user?.role !== requiredRole) {
   131→    // Easy Salon e Tenant Admin podem acessar tudo (admin e salon)
   132→    const isSuperAdmin = user?.role === 'Easy Salon' || user?.role === 'Tenant Admin';
   133→    // Administrador pode acessar área do salão
   134→    const isAdminInSalon = user?.role === 'Administrador' && !location.pathname.startsWith('/admin/');
   135→
   136→    if (!isSuperAdmin && !isAdminInSalon) {
   137→      hasPermission = false;
   138→    }
   139→  }
   140→
   141→  if (!hasPermission) {
   142→    return null;
   143→  }
   144→
   145→  return (
   146→    <>
   147→      {children}
   148→      {location.pathname !== '/onboarding' && <WhatsAppButton />}
   149→    </>
   150→  );
   151→}

